<#
.SYNOPSIS
    gurudev-docs-update.ps1 - Atualiza TODOS os documentos do gurudev-core
.DESCRIPTION
    Script autocontido que reescreve 6 arquivos e aplica substituicoes em 9 arquivos.
    EXECUTAR NA PASTA RAIZ DO REPOSITORIO gurudev-core.
#>

Write-Host "" -ForegroundColor Cyan
Write-Host "=== GuruDev Docs - Atualizacao Completa ===" -ForegroundColor Cyan
Write-Host "=== Hubstry-DeepTech ===" -ForegroundColor Cyan

$ErrorActionPreference = "Stop"

if (-not (Test-Path ".git")) {
    Write-Host "ERRO: .git nao encontrado! Execute na pasta raiz do gurudev-core." -ForegroundColor Red
    exit 1
}

# === BASE64 ENCODED FILES ===
$B64_README_MD = ""
$B64_README_EN_MD = ""
$B64_FINANCIAL_MODEL_MD = ""
$B64_FINANCIAL_MODEL_EN_MD = ""
$B64_FOUNDER_PROFILE_MD = ""
$B64_FOUNDER_PROFILE_EN_MD = ""

# === FUNCTION TO WRITE FILES ===
function Write-FileFromBase64($b64, $path, $label) {
    $bytes = [System.Convert]::FromBase64String($b64)
    $content = [System.Text.Encoding]::UTF8.GetString($bytes)
    [System.IO.File]::WriteAllText($path, $content, [System.Text.UTF8Encoding]::new($false))
    Write-Host "  [OK] $label" -ForegroundColor Green
}

Write-Host "[1/6] Escrevendo README.md..." -ForegroundColor White
Write-FileFromBase64 $B64_README_MD "README.md" "README.md"
Write-Host "[2/6] Escrevendo README_EN.md..." -ForegroundColor White
Write-FileFromBase64 $B64_README_EN_MD "README_EN.md" "README_EN.md"
Write-Host "[3/6] Escrevendo FINANCIAL_MODEL.md..." -ForegroundColor White
Write-FileFromBase64 $B64_FINANCIAL_MODEL_MD "FINANCIAL_MODEL.md" "FINANCIAL_MODEL.md"
Write-Host "[4/6] Escrevendo FINANCIAL_MODEL_EN.md..." -ForegroundColor White
Write-FileFromBase64 $B64_FINANCIAL_MODEL_EN_MD "FINANCIAL_MODEL_EN.md" "FINANCIAL_MODEL_EN.md"
Write-Host "[5/6] Escrevendo FOUNDER_PROFILE.md..." -ForegroundColor White
Write-FileFromBase64 $B64_FOUNDER_PROFILE_MD "FOUNDER_PROFILE.md" "FOUNDER_PROFILE.md"
Write-Host "[6/6] Escrevendo FOUNDER_PROFILE_EN.md..." -ForegroundColor White
Write-FileFromBase64 $B64_FOUNDER_PROFILE_EN_MD "FOUNDER_PROFILE_EN.md" "FOUNDER_PROFILE_EN.md"

# === TEXT REPLACEMENTS ===
$emailOld = "guilhermemachado@hubstry.com"
$emailNew = "guilhermemachado.ceo@hubstry.dev"
$siteOld = "hubstry.com"
$siteNew = "www.hubstry.dev"
$urlOld = "https://github.com/seu-usuario/alexandria"
$urlNew = "https://github.com/Hubstry-DeepTech/gurudev-core"
$cont = 0

function Sub-Arquivo($caminho, $antigo, $novo, $descricao) {
    if (-not (Test-Path $caminho)) {
        Write-Host "  [PULADO] $caminho nao encontrado" -ForegroundColor Yellow
        return
    }
    $c = [System.IO.File]::ReadAllText($caminho, [System.Text.Encoding]::UTF8)
    if ($c.Contains($antigo)) {
        $c = $c.Replace($antigo, $novo)
        [System.IO.File]::WriteAllText($caminho, $c, [System.Text.UTF8Encoding]::new($false))
        Write-Host "  [OK] $descricao" -ForegroundColor Green
        $script:cont++
    } else {
        Write-Host "  [--] $descricao (ja atualizado)" -ForegroundColor DarkGray
    }
}

Write-Host ""
Write-Host "=== Aplicando substituicoes de contato ===" -ForegroundColor Cyan

Write-Host "[1/9] CONTRIBUTING.md" -ForegroundColor White
Sub-Arquivo "CONTRIBUTING.md" $emailOld $emailNew "Email atualizado"
Write-Host "[2/9] CONTRIBUTING_EN.md" -ForegroundColor White
Sub-Arquivo "CONTRIBUTING_EN.md" $emailOld $emailNew "Email atualizado"
Write-Host "[3/9] ALEXANDRIA_README.md" -ForegroundColor White
Sub-Arquivo "ALEXANDRIA_README.md" $emailOld $emailNew "Email atualizado"
Write-Host "[4/9] ALEXANDRIA_README_EN.md" -ForegroundColor White
Sub-Arquivo "ALEXANDRIA_README_EN.md" $emailOld $emailNew "Email atualizado"
Write-Host "[5/9] OFFICIAL_LINKS.md" -ForegroundColor White
Sub-Arquivo "OFFICIAL_LINKS.md" "https://hubstry.com/" "https://www.hubstry.dev" "Site atualizado"
Write-Host "[6/9] roadmap.md" -ForegroundColor White
Sub-Arquivo "roadmap.md" "Participacao no programa **Artemisia Potencia UP 2025.2**, focando em impacto e escalabilidade." "Participacao em programas de aceleracao e fomento, focando em impacto e escalabilidade." "Artemisia removida (1)"
Sub-Arquivo "roadmap.md" "(Microsoft, Google, Santander, Artemisia)." "(Microsoft, Google, Santander)." "Artemisia removida (2)"
Sub-Arquivo "roadmap.md" "Santander Explorer, Microsoft for Startups, GitHub Education, Google Gemini e Artemisia" "Santander Explorer, Microsoft for Startups, GitHub Education e Google Gemini" "Artemisia removida (3)"
Write-Host "[7/9] roadmap_EN.md" -ForegroundColor White
Sub-Arquivo "roadmap_EN.md" "Participation in the **Artemisia Potencia UP 2025.2** program, focusing on impact and scalability." "Participation in acceleration and funding programs, focusing on impact and scalability." "Artemisia removida EN (1)"
Sub-Arquivo "roadmap_EN.md" "(Microsoft, Google, Santander, Artemisia)." "(Microsoft, Google, Santander)." "Artemisia removida EN (2)"
Sub-Arquivo "roadmap_EN.md" "Santander Explorer, Microsoft for Startups, GitHub Education, Google Gemini, and Artemisia" "Santander Explorer, Microsoft for Startups, GitHub Education, and Google Gemini" "Artemisia removida EN (3)"
Write-Host "[8/9] pyproject.toml" -ForegroundColor White
Sub-Arquivo "pyproject.toml" $emailOld $emailNew "Email atualizado"
Write-Host "[9/9] alexandria/__init__.py" -ForegroundColor White
Sub-Arquivo "alexandria/__init__.py" $emailOld $emailNew "Email atualizado"
Sub-Arquivo "alexandria/__init__.py" $urlOld $urlNew "URL corrigida"

Write-Host ""
Write-Host "=== Concluido! $cont substituicoes + 6 arquivos reescritos ===" -ForegroundColor Cyan

Write-Host "PROXIMOS PASSOS:" -ForegroundColor Yellow
Write-Host "  git add -A" -ForegroundColor White
Write-Host "  git commit -m `"docs: atualiza README, modelo financeiro, contatos e remove Artemisia`"" -ForegroundColor White
Write-Host "  git pull --rebase origin main" -ForegroundColor White
Write-Host "  git push origin main" -ForegroundColor White
